/* ---- INC ---- */
static void
op_inc_zp(struct cpu *cpu)
{
	uint16_t a = addr_zp(cpu);
	uint8_t orig = read_byte(cpu, a);
	write_byte_dummy(cpu,
	    a,
	    orig); /* NMOS dummy write of unmodified value */
	write_byte(cpu, a, orig + 1);
	update_nz(cpu, orig + 1);
	cpu->last_cycles = 5;
}
