static void
op_lsr_acc(struct cpu *cpu)
{
	read_byte(cpu, cpu->pc); /* cycle 2: dummy read */
	set_flag(cpu, FLAG_CARRY, (cpu->a & 0x01) != 0);
	cpu->a >>= 1;
	update_nz(cpu, cpu->a);
	cpu->last_cycles = 2;
}
