	write_byte_dummy(cpu, a, t); /* NMOS dummy write of unmodified value */
	set_flag(cpu, FLAG_CARRY, (t & 0x01) != 0);
	t >>= 1;
	write_byte(cpu, a, t);
	update_nz(cpu, t);
	cpu->last_cycles = 5;
