/* ---- DCP (DEC+CMP, RMW) ---- */
static void
dcp_core(struct cpu *cpu, uint16_t a)
{
	uint8_t t;
	int diff;

	t = read_byte(cpu, a);
	write_byte_dummy(cpu, a, t);
	t--;
	diff = cpu->a - t;
	set_flag(cpu, FLAG_CARRY, cpu->a >= t);
	set_flag(cpu, FLAG_ZERO, (diff & 0xFF) == 0);
	set_flag(cpu, FLAG_NEGATIVE, (diff & 0x80) != 0);
	write_byte(cpu, a, t);
}
